 * Default webhook preferences for new users.
 * Enabled by default — webhook delivery has no per-message cost.
 */
export function getDefaultWebhookPreferences(): ChannelPreferences {
  return {
    enabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

