/**
 * Notification preference validation — pure functions for checking
 * whether a notification should be sent based on user preferences.
 *
 * No side effects, no database calls. Operates on already-fetched
 * preference objects.
 */

import type { UserPreferences, ChannelPreferences } from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';

/**
 * Determine whether a notification should be sent based on stored preferences.
 *
 * Returns true if the notification should proceed, false if suppressed.
 * If preferences is null/undefined, returns true (send everything by default).
 *
 * For channels where per-channel preferences are not yet set on the
 * preferences object, falls back to true (backward compatibility).
 */
export function shouldSendNotification(
  prefs: UserPreferences | undefined,
  channel: NotificationChannel,
  type: NotificationType,
): boolean {
  if (!prefs) {
    return true;
  }

  if (channel === 'email') {
    if (!prefs.email.enabled) {
      return false;
    }
    if (!prefs.email.subscribedCategories.includes(type)) {
      return false;
    }
    return true;
  }

  if (channel === 'sms') {
    return checkChannelPreferences(prefs.sms, type);
  }

  if (channel === 'webhook') {
    return checkChannelPreferences(prefs.webhook, type);
  }

  // Unknown channels are allowed by default
  return true;
}

/**
 * Check a generic channel's preferences. If the channel preferences
 * are not set (undefined), allows the notification (backward compat).
 */
function checkChannelPreferences(
  channelPrefs: ChannelPreferences | undefined,
  type: NotificationType,
): boolean {
  if (!channelPrefs) {
    return true;
  }
  if (!channelPrefs.enabled) {
    return false;
  }
  if (!channelPrefs.subscribedCategories.includes(type)) {
    return false;
  }
  return true;
}

