import { describe, it, expect } from 'vitest';
import { shouldSendNotification } from '../../src/validators/notification.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

function makePrefs(overrides?: {
  email?: Partial<UserPreferences['email']>;
  sms?: UserPreferences['sms'];
  webhook?: UserPreferences['webhook'];
}): UserPreferences {
  return {
    id: 'pref-1',
    userId: 'user-1',
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: ['order-confirmation', 'order-status-update', 'welcome', 'account-updated'],
      ...overrides?.email,
    },
    sms: overrides?.sms,
    webhook: overrides?.webhook,
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

describe('Notification Validators', () => {
  describe('shouldSendNotification', () => {
    it('should return true when preferences are undefined', () => {
      expect(shouldSendNotification(undefined, 'email', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and subscribed', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      const prefs = makePrefs({ email: { enabled: false } });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should return false when not subscribed to category', () => {
      const prefs = makePrefs({ email: { subscribedCategories: ['welcome'] } });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should return true when subscribed to specific category', () => {
      const prefs = makePrefs({ email: { subscribedCategories: ['order-confirmation'] } });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(true);
    });

    it('should return true for channels without preferences set (backward compat)', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(true);
      expect(shouldSendNotification(prefs, 'webhook', 'welcome')).toBe(true);
    });
  });

  describe('shouldSendNotification — SMS channel', () => {
    it('should return false when SMS is disabled', () => {
      const prefs = makePrefs({
        sms: {
          enabled: false,
          subscribedCategories: ['order-confirmation', 'order-status-update', 'welcome', 'account-updated'],
        },
      });
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled and subscribed', () => {
      const prefs = makePrefs({
        sms: {
          enabled: true,
          subscribedCategories: ['order-confirmation'],
        },
      });
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(true);
    });

    it('should return false when not subscribed to SMS category', () => {
      const prefs = makePrefs({
        sms: {
          enabled: true,
          subscribedCategories: ['welcome'],
        },
      });
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(false);
    });

    it('should allow SMS when sms preferences are undefined (backward compat)', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(true);
    });
  });

  describe('shouldSendNotification — webhook channel', () => {
    it('should return false when webhook is disabled', () => {
      const prefs = makePrefs({
        webhook: {
          enabled: false,
          subscribedCategories: ['order-confirmation', 'order-status-update', 'welcome', 'account-updated'],
        },
      });
      expect(shouldSendNotification(prefs, 'webhook', 'order-confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled and subscribed', () => {
      const prefs = makePrefs({
        webhook: {
          enabled: true,
          subscribedCategories: ['order-confirmation'],
        },
      });
      expect(shouldSendNotification(prefs, 'webhook', 'order-confirmation')).toBe(true);
    });

    it('should return false when not subscribed to webhook category', () => {
      const prefs = makePrefs({
        webhook: {
          enabled: true,
          subscribedCategories: ['welcome'],
        },
      });
      expect(shouldSendNotification(prefs, 'webhook', 'order-confirmation')).toBe(false);
    });

    it('should allow webhook when webhook preferences are undefined (backward compat)', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'webhook', 'order-confirmation')).toBe(true);
    });
  });

  describe('shouldSendNotification — unknown channels', () => {
    it('should return true for in-app channel with no specific preferences', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'in-app', 'order-confirmation')).toBe(true);
    });
  });

  describe('shouldSendNotification — cross-channel independence', () => {
    it('should allow email while suppressing SMS', () => {
      const prefs = makePrefs({
        email: { enabled: true },
        sms: { enabled: false, subscribedCategories: ['order-confirmation'] },
      });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(true);
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(false);
    });

    it('should suppress email while allowing SMS', () => {
      const prefs = makePrefs({
        email: { enabled: false },
        sms: { enabled: true, subscribedCategories: ['order-confirmation'] },
      });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(false);
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(true);
    });

    it('should handle different category subscriptions per channel', () => {
      const prefs = makePrefs({
        email: { subscribedCategories: ['order-confirmation'] },
        sms: { enabled: true, subscribedCategories: ['welcome'] },
        webhook: { enabled: true, subscribedCategories: ['account-updated'] },
      });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(true);
      expect(shouldSendNotification(prefs, 'email', 'welcome')).toBe(false);
      expect(shouldSendNotification(prefs, 'sms', 'welcome')).toBe(true);
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(false);
      expect(shouldSendNotification(prefs, 'webhook', 'account-updated')).toBe(true);
      expect(shouldSendNotification(prefs, 'webhook', 'welcome')).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { NotificationType } from '../../src/models/notification.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create default SMS preferences (disabled by default)', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(false);
      expect(prefs.sms!.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create default webhook preferences (enabled by default)', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repository.count()).toBe(1);
    });

    it('should create separate preferences for different users', () => {
      const prefs1 = service.getOrCreatePreferences('user-1');
      const prefs2 = service.getOrCreatePreferences('user-2');

      expect(prefs1.userId).toBe('user-1');
      expect(prefs2.userId).toBe('user-2');
      expect(prefs1.id).not.toBe(prefs2.id);
      expect(repository.count()).toBe(2);
    });
  });

  describe('updatePreferences', () => {
    it('should disable email notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      // Other fields remain unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should change email frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily-digest' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-confirmation'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should create preferences if none exist when updating', () => {
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.enabled).toBe(false);
    });

    it('should persist updates across reads', () => {
      service.updatePreferences('user-1', {
        email: { frequency: 'weekly-digest', subscribedCategories: ['welcome'] },
      });

      const prefs = service.getOrCreatePreferences('user-1');
      expect(prefs.email.frequency).toBe('weekly-digest');
      expect(prefs.email.subscribedCategories).toEqual(['welcome']);
    });

    it('should enable SMS notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        sms: { enabled: true },
      });

      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update SMS subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        sms: { enabled: true, subscribedCategories: ['order-confirmation'] },
      });

      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should disable webhook notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: false },
      });

      expect(updated.webhook!.enabled).toBe(false);
      expect(updated.webhook!.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update multiple channels at once', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { subscribedCategories: ['order-confirmation'] },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms!.enabled).toBe(true);
      expect(updated.webhook!.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should preserve other channels when updating one', () => {
      service.getOrCreatePreferences('user-1');
      service.updatePreferences('user-1', { sms: { enabled: true } });
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      // SMS should still be enabled
      expect(updated.sms!.enabled).toBe(true);
      expect(updated.email.enabled).toBe(false);
    });
  });

  describe('shouldSendNotification', () => {
    it('should allow notifications when no preferences are stored', () => {
      const result = service.shouldSendNotification('user-1', 'email', 'order-confirmation');
      expect(result).toBe(true);
    });

    it('should allow notifications with default preferences', () => {
      service.getOrCreatePreferences('user-1');
      const result = service.shouldSendNotification('user-1', 'email', 'order-confirmation');
      expect(result).toBe(true);
    });

    it('should suppress notifications when email is disabled', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      const result = service.shouldSendNotification('user-1', 'email', 'order-confirmation');
      expect(result).toBe(false);
    });

    it('should suppress notifications for unsubscribed categories', () => {
      service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-confirmation'] },
      });

      expect(service.shouldSendNotification('user-1', 'email', 'order-confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'email', 'order-status-update')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'email', 'welcome')).toBe(false);
    });

    it('should suppress SMS when SMS is disabled', () => {
      service.getOrCreatePreferences('user-1');
      // SMS is disabled by default
      const result = service.shouldSendNotification('user-1', 'sms', 'order-confirmation');
      expect(result).toBe(false);
    });

    it('should allow SMS when SMS is enabled', () => {
      service.updatePreferences('user-1', { sms: { enabled: true } });
      const result = service.shouldSendNotification('user-1', 'sms', 'order-confirmation');
      expect(result).toBe(true);
    });

    it('should suppress SMS for unsubscribed categories', () => {
      service.updatePreferences('user-1', {
        sms: { enabled: true, subscribedCategories: ['welcome'] },
      });
